# Constants
DEFAULT_TIMEOUT = 30  # seconds
MAX_RETRIES = 3
RETRY_BACKOFF_FACTOR = 0.5
ALLOWED_SCHEMES = ("http", "https")


class KongAdminClientError(Exception):
    """Custom exception for Kong Admin Client errors."""
