    # ---- Route Management ----

    def create_route(
        self,
        service_name_or_id: str,
        name: Optional[str] = None,
        paths: Optional[list[str]] = None,
        hosts: Optional[list[str]] = None,
        methods: Optional[list[str]] = None,
        protocols: Optional[list[str]] = None,
        strip_path: bool = True,
        preserve_host: bool = False,
        headers: Optional[dict[str, list[str]]] = None,
        tags: Optional[list[str]] = None,
    ) -> dict[str, Any]:
        """
        Create a route for a service.

        Args:
            service_name_or_id: Service name or ID to attach route to
            name: Route name
            paths: List of paths to match
            hosts: List of hosts to match
            methods: List of HTTP methods to match
            protocols: List of protocols (http, https)
            strip_path: Strip matched path prefix
            preserve_host: Preserve original Host header
            headers: Headers to match
            tags: Optional tags

        Returns:
            Created route data
        """
        if not paths and not hosts and not methods and not headers:
            raise ValueError(
                "At least one of paths, hosts, methods, or headers must be specified"
            )

        valid_methods = {"GET", "POST", "PUT", "PATCH", "DELETE", "OPTIONS", "HEAD", "TRACE", "CONNECT"}
        if methods:
            methods_upper = [m.upper() for m in methods]
            invalid = set(methods_upper) - valid_methods
            if invalid:
                raise ValueError(f"Invalid HTTP methods: {invalid}")
            methods = methods_upper

        if protocols:
            valid_route_protocols = {"http", "https", "grpc", "grpcs", "tcp", "tls", "udp"}
            invalid_protocols = set(protocols) - valid_route_protocols
            if invalid_protocols:
                raise ValueError(f"Invalid protocols: {invalid_protocols}")

        data: dict[str, Any] = {
            "service": {"name": service_name_or_id} if not self._is_uuid(service_name_or_id) else {"id": service_name_or_id},
            "strip_path": strip_path,
            "preserve_host": preserve_host,
        }

        if name:
            data["name"] = name
        if paths:
            data["paths"] = paths
        if hosts:
            data["hosts"] = hosts
        if methods:
            data["methods"] = methods
        if protocols:
            data["protocols"] = protocols
        if headers:
            data["headers"] = headers
        if tags:
            data["tags"] = tags

        logger.info(
            "Creating route '%s' for service '%s' (paths: %s, hosts: %s)",
            name or "unnamed",
            service_name_or_id,
            paths,
            hosts,
        )
        result = self._request("POST", "/routes", data=data)
        logger.info("Route created: %s (id: %s)", name or "unnamed", result.get("id"))
        return result

